String.prototype.gbCut = function(n){
  if(!(/^[0-9]*[1-9][0-9]*$/).test(n)){return this};
  if(n == 0){return this};
  var k = 0;
  for (var i=0; i<this.length; i++) {
    if (this.charCodeAt(i)<=127) {
      k += 1;
    } else {
      k += 2;
    }
    if (k>n) {
      var ns = this.substr(0,i);
      return (ns);
    }
  }
  return (this);
};

function commafy(num){
  num = num+"";
  var re=/(-?\d+)(\d{3})/
  while(re.test(num)){
    num=num.replace(re,"$1,$2")
  }
  return num;
}
